function ProductCard({ product, isFavorite, onToggleFavorite, onClick, onBuy, onAddToCart }) {
  return (
    <div className="prod-card" onClick={onClick} role={onClick ? "link" : undefined} tabIndex={onClick ? 0 : undefined}>
      <div className="prod-img" style={!product.image ? { background: product.gradient } : undefined}>
        {product.image ? (
          <img src={product.image} alt={product.name} loading="lazy" />
        ) : (
          <span className="prod-ph">Product image</span>
        )}
        {product.badge && <div className="prod-badge">{product.badge}</div>}
        <button
          className="prod-heart"
          style={{ color: isFavorite ? "var(--b2)" : "var(--ink2)" }}
          aria-label={isFavorite ? "Remove from wishlist" : "Add to wishlist"}
          onClick={(e) => {
            e.stopPropagation();
            onToggleFavorite(product.id);
          }}
        >
          <Heart size={15} fill={isFavorite ? "currentColor" : "none"} />
        </button>
      </div>
      <div className="prod-info">
        <p className="prod-name">{product.name}</p>
        <p className="prod-price">{NAIRA(product.price)}</p>
        <div className="prod-swatches">
          {product.swatches.map((c, i) => (
            <div key={i} className="sw" style={{ background: c }} />
          ))}
        </div>
        {onBuy && (
          <button
            className="prod-buy-btn"
            onClick={e => { e.stopPropagation(); onBuy(product); }}
          >Buy Now</button>
        )}
        {onAddToCart && (
          <button
            className="prod-cart-btn"
            onClick={e => { e.stopPropagation(); onAddToCart(product); }}
          >Add To Cart</button>
        )}
      </div>
    </div>
  );
}

