function ContactPage() {
  const [form, setForm] = useState({ name: "", email: "", subject: "", message: "" });
  const [status, setStatus] = useState(null); // null | 'error' | 'sent'

  function update(field) {
    return (e) => setForm((f) => ({ ...f, [field]: e.target.value }));
  }

  function handleSubmit(e) {
    e.preventDefault();
    if (!form.name.trim() || !form.email.trim() || !form.message.trim()) {
      setStatus("error");
      return;
    }
    const subject = encodeURIComponent(form.subject.trim() || "Website enquiry");
    const body = encodeURIComponent(`Name: ${form.name}\nEmail: ${form.email}\n\n${form.message}`);
    window.location.href = `mailto:contact@patiencebyibiyebrown.shop?subject=${subject}&body=${body}`;
    setStatus("sent");
  }

  return (
    <div>
      <div className="ct-header">
        <p className="ct-kicker">Reach Out</p>
        <h1 className="ct-h1">
          Get in <em>Touch</em>
        </h1>
      </div>
      <section className="ct-body">
        <div className="ct-info">
          <p className="ct-kicker">Confidence · Style · Patience</p>
          <h3>We'd love to hear from you</h3>
          <p>For orders, collaborations, custom pieces, or simply to share how a piece made you feel — we'd love to hear from you.</p>
          <div className="ct-rows">
            <div className="ct-row">
              <Mail size={16} className="ct-ic" />
              <a className="ct-v" href="mailto:contact@patiencebyibiyebrown.shop">
                contact@patiencebyibiyebrown.shop
              </a>
            </div>
            <div className="ct-row">
              <Instagram size={16} className="ct-ic" />
              <a className="ct-h" href="https://instagram.com/patiencebyibiyebrown.shop" target="_blank" rel="noopener noreferrer">
                @patiencebyibiyebrown.shop
              </a>
            </div>
            <div className="ct-row">
              <Music2 size={16} className="ct-ic" />
              <a className="ct-h" href="https://tiktok.com/@patiencebyibiyebrown.shop" target="_blank" rel="noopener noreferrer">
                @patiencebyibiyebrown.shop
              </a>
            </div>
            <div className="ct-row">
              <MapPin size={16} className="ct-ic" />
              <span className="ct-v">Lagos, Nigeria</span>
            </div>
          </div>
          <div className="ct-quote">
            <p>“Many women have done excellent things, but you surpass them all.”</p>
            <p>Proverbs 31:29</p>
          </div>
        </div>
        <form className="ct-form" onSubmit={handleSubmit}>
          <div className="ff">
            <label htmlFor="cn">Your name</label>
            <input type="text" id="cn" placeholder="e.g. Adaeze Okonkwo" autoComplete="name" value={form.name} onChange={update("name")} />
          </div>
          <div className="ff">
            <label htmlFor="ce">Email address</label>
            <input type="email" id="ce" placeholder="hello@email.com" autoComplete="email" value={form.email} onChange={update("email")} />
          </div>
          <div className="ff">
            <label htmlFor="cs">Subject</label>
            <input type="text" id="cs" placeholder="e.g. Custom order enquiry" value={form.subject} onChange={update("subject")} />
          </div>
          <div className="ff">
            <label htmlFor="cm">Message</label>
            <textarea id="cm" placeholder="I'd love to enquire about..." value={form.message} onChange={update("message")} />
          </div>
          {status === "error" && <p className="form-msg form-msg-error">Please fill in your name, email, and message.</p>}
          {status === "sent" && <p className="form-msg form-msg-ok">Opening your email app now — thank you for reaching out!</p>}
          <button type="submit" className="btn-solid" style={{ alignSelf: "flex-start" }}>
            Send message →
          </button>
        </form>
      </section>
    </div>
  );
}

